class DynamicMessageRouter:
    def __init__(
        self,
        static_handlers: Optional[Dict[str, Union[str, Callable[[Dict[str, Any], TransactionContext], Any]]]] = None,
        allow_dynamic_imports: bool = True,
    ) -> None:
        self.static_handlers = static_handlers or {}
        self.allow_dynamic_imports = allow_dynamic_imports

    def resolve(self, payload: Dict[str, Any]) -> Callable[[Dict[str, Any], TransactionContext], Any]:
        handler = payload.get("handler")
        event_type = payload.get("event_type")

        target = None
